
public class Ex05_증감연산자 {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		// 단항연산자
		// ++변수, --변수, 변수++, 변수--
		int num = 5;
		
		System.out.println(++num);
		System.out.println(num++);
		System.out.println(num);
		// num = num+1;
		// num+=1;
		--num;
		
		System.out.println(num);
		
		num--;
		
		System.out.println(num);
		
	}

}
